<?php/** * AquaLuxe Customizer Class * * This class handles the theme customizer for the AquaLuxe theme. * * @package AquaLuxe */// Exit if accessed directlyif (!defined('ABSPATH')) {    exit;}/** * AquaLuxe Customizer Class */class AquaLuxe_Customizer {    /**     * Instance of the class     *     * @var AquaLuxe_Customizer     */    private static $instance = null;    /**     * Constructor     */    private function __construct() {        // Register hooks        add_action('customize_register', [$this, 'register_customizer']);        add_action('customize_preview_init', [$this, 'preview_init']);        add_action('customize_controls_enqueue_scripts', [$this, 'controls_enqueue_scripts']);        add_action('wp_head', [$this, 'output_customizer_css']);    }    /**     * Get instance of the class     *     * @return AquaLuxe_Customizer     */    public static function get_instance() {        if (is_null(self::$instance)) {            self::$instance = new self();        }        return self::$instance;    }    /**     * Register customizer     *     * @param WP_Customize_Manager $wp_customize     */    public function register_customizer($wp_customize) {        // Add panels        $this->add_panels($wp_customize);        // Add sections        $this->add_sections($wp_customize);        // Add settings and controls        $this->add_general_settings($wp_customize);        $this->add_header_settings($wp_customize);        $this->add_footer_settings($wp_customize);        $this->add_typography_settings($wp_customize);        $this->add_colors_settings($wp_customize);        $this->add_layout_settings($wp_customize);        $this->add_blog_settings($wp_customize);        $this->add_social_settings($wp_customize);        $this->add_contact_settings($wp_customize);        $this->add_performance_settings($wp_customize);        $this->add_modules_settings($wp_customize);        // Add WooCommerce settings if active        if (aqualuxe_is_woocommerce_active()) {            $this->add_woocommerce_settings($wp_customize);        }    }    /**     * Add panels     *     * @param WP_Customize_Manager $wp_customize     */    private function add_panels($wp_customize) {        // Theme Options Panel        $wp_customize->add_panel('aqualuxe_theme_options', [            'title' => __('AquaLuxe Theme Options', 'aqualuxe'),            'description' => __('Customize your theme settings', 'aqualuxe'),            'priority' => 10,        ]);        // Header Panel        $wp_customize->add_panel('aqualuxe_header_panel', [            'title' => __('Header', 'aqualuxe'),            'description' => __('Customize header settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 20,        ]);        // Footer Panel        $wp_customize->add_panel('aqualuxe_footer_panel', [            'title' => __('Footer', 'aqualuxe'),            'description' => __('Customize footer settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 30,        ]);        // Typography Panel        $wp_customize->add_panel('aqualuxe_typography_panel', [            'title' => __('Typography', 'aqualuxe'),            'description' => __('Customize typography settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 40,        ]);        // Colors Panel        $wp_customize->add_panel('aqualuxe_colors_panel', [            'title' => __('Colors', 'aqualuxe'),            'description' => __('Customize color settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 50,        ]);        // Layout Panel        $wp_customize->add_panel('aqualuxe_layout_panel', [            'title' => __('Layout', 'aqualuxe'),            'description' => __('Customize layout settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 60,        ]);        // Blog Panel        $wp_customize->add_panel('aqualuxe_blog_panel', [            'title' => __('Blog', 'aqualuxe'),            'description' => __('Customize blog settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 70,        ]);        // Modules Panel        $wp_customize->add_panel('aqualuxe_modules_panel', [            'title' => __('Modules', 'aqualuxe'),            'description' => __('Customize module settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 80,        ]);        // WooCommerce Panel        if (aqualuxe_is_woocommerce_active()) {            $wp_customize->add_panel('aqualuxe_woocommerce_panel', [                'title' => __('WooCommerce', 'aqualuxe'),                'description' => __('Customize WooCommerce settings', 'aqualuxe'),                'panel' => 'aqualuxe_theme_options',                'priority' => 90,            ]);        }    }    /**     * Add sections     *     * @param WP_Customize_Manager $wp_customize     */    private function add_sections($wp_customize) {        // General Section        $wp_customize->add_section('aqualuxe_general_section', [            'title' => __('General', 'aqualuxe'),            'description' => __('General theme settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 10,        ]);        // Header Sections        $wp_customize->add_section('aqualuxe_header_general_section', [            'title' => __('General', 'aqualuxe'),            'description' => __('General header settings', 'aqualuxe'),            'panel' => 'aqualuxe_header_panel',            'priority' => 10,        ]);        $wp_customize->add_section('aqualuxe_header_top_bar_section', [            'title' => __('Top Bar', 'aqualuxe'),            'description' => __('Header top bar settings', 'aqualuxe'),            'panel' => 'aqualuxe_header_panel',            'priority' => 20,        ]);        $wp_customize->add_section('aqualuxe_header_navigation_section', [            'title' => __('Navigation', 'aqualuxe'),            'description' => __('Header navigation settings', 'aqualuxe'),            'panel' => 'aqualuxe_header_panel',            'priority' => 30,        ]);        $wp_customize->add_section('aqualuxe_header_mobile_section', [            'title' => __('Mobile', 'aqualuxe'),            'description' => __('Mobile header settings', 'aqualuxe'),            'panel' => 'aqualuxe_header_panel',            'priority' => 40,        ]);        // Footer Sections        $wp_customize->add_section('aqualuxe_footer_general_section', [            'title' => __('General', 'aqualuxe'),            'description' => __('General footer settings', 'aqualuxe'),            'panel' => 'aqualuxe_footer_panel',            'priority' => 10,        ]);        $wp_customize->add_section('aqualuxe_footer_widgets_section', [            'title' => __('Widgets', 'aqualuxe'),            'description' => __('Footer widgets settings', 'aqualuxe'),            'panel' => 'aqualuxe_footer_panel',            'priority' => 20,        ]);        $wp_customize->add_section('aqualuxe_footer_bottom_section', [            'title' => __('Bottom Bar', 'aqualuxe'),            'description' => __('Footer bottom bar settings', 'aqualuxe'),            'panel' => 'aqualuxe_footer_panel',            'priority' => 30,        ]);        // Typography Sections        $wp_customize->add_section('aqualuxe_typography_general_section', [            'title' => __('General', 'aqualuxe'),            'description' => __('General typography settings', 'aqualuxe'),            'panel' => 'aqualuxe_typography_panel',            'priority' => 10,        ]);        $wp_customize->add_section('aqualuxe_typography_headings_section', [            'title' => __('Headings', 'aqualuxe'),            'description' => __('Headings typography settings', 'aqualuxe'),            'panel' => 'aqualuxe_typography_panel',            'priority' => 20,        ]);        $wp_customize->add_section('aqualuxe_typography_body_section', [            'title' => __('Body', 'aqualuxe'),            'description' => __('Body typography settings', 'aqualuxe'),            'panel' => 'aqualuxe_typography_panel',            'priority' => 30,        ]);        // Colors Sections        $wp_customize->add_section('aqualuxe_colors_general_section', [            'title' => __('General', 'aqualuxe'),            'description' => __('General color settings', 'aqualuxe'),            'panel' => 'aqualuxe_colors_panel',            'priority' => 10,        ]);        $wp_customize->add_section('aqualuxe_colors_header_section', [            'title' => __('Header', 'aqualuxe'),            'description' => __('Header color settings', 'aqualuxe'),            'panel' => 'aqualuxe_colors_panel',            'priority' => 20,        ]);        $wp_customize->add_section('aqualuxe_colors_footer_section', [            'title' => __('Footer', 'aqualuxe'),            'description' => __('Footer color settings', 'aqualuxe'),            'panel' => 'aqualuxe_colors_panel',            'priority' => 30,        ]);        $wp_customize->add_section('aqualuxe_colors_buttons_section', [            'title' => __('Buttons', 'aqualuxe'),            'description' => __('Button color settings', 'aqualuxe'),            'panel' => 'aqualuxe_colors_panel',            'priority' => 40,        ]);        // Layout Sections        $wp_customize->add_section('aqualuxe_layout_general_section', [            'title' => __('General', 'aqualuxe'),            'description' => __('General layout settings', 'aqualuxe'),            'panel' => 'aqualuxe_layout_panel',            'priority' => 10,        ]);        $wp_customize->add_section('aqualuxe_layout_pages_section', [            'title' => __('Pages', 'aqualuxe'),            'description' => __('Page layout settings', 'aqualuxe'),            'panel' => 'aqualuxe_layout_panel',            'priority' => 20,        ]);        $wp_customize->add_section('aqualuxe_layout_blog_section', [            'title' => __('Blog', 'aqualuxe'),            'description' => __('Blog layout settings', 'aqualuxe'),            'panel' => 'aqualuxe_layout_panel',            'priority' => 30,        ]);        // Blog Sections        $wp_customize->add_section('aqualuxe_blog_general_section', [            'title' => __('General', 'aqualuxe'),            'description' => __('General blog settings', 'aqualuxe'),            'panel' => 'aqualuxe_blog_panel',            'priority' => 10,        ]);        $wp_customize->add_section('aqualuxe_blog_archive_section', [            'title' => __('Archive', 'aqualuxe'),            'description' => __('Blog archive settings', 'aqualuxe'),            'panel' => 'aqualuxe_blog_panel',            'priority' => 20,        ]);        $wp_customize->add_section('aqualuxe_blog_single_section', [            'title' => __('Single Post', 'aqualuxe'),            'description' => __('Single post settings', 'aqualuxe'),            'panel' => 'aqualuxe_blog_panel',            'priority' => 30,        ]);        // Social Section        $wp_customize->add_section('aqualuxe_social_section', [            'title' => __('Social Media', 'aqualuxe'),            'description' => __('Social media settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 100,        ]);        // Contact Section        $wp_customize->add_section('aqualuxe_contact_section', [            'title' => __('Contact Information', 'aqualuxe'),            'description' => __('Contact information settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 110,        ]);        // Performance Section        $wp_customize->add_section('aqualuxe_performance_section', [            'title' => __('Performance', 'aqualuxe'),            'description' => __('Performance settings', 'aqualuxe'),            'panel' => 'aqualuxe_theme_options',            'priority' => 120,        ]);        // WooCommerce Sections        if (aqualuxe_is_woocommerce_active()) {            $wp_customize->add_section('aqualuxe_woocommerce_general_section', [                'title' => __('General', 'aqualuxe'),                'description' => __('General WooCommerce settings', 'aqualuxe'),                'panel' => 'aqualuxe_woocommerce_panel',                'priority' => 10,            ]);            $wp_customize->add_section('aqualuxe_woocommerce_shop_section', [                'title' => __('Shop', 'aqualuxe'),                'description' => __('Shop page settings', 'aqualuxe'),                'panel' => 'aqualuxe_woocommerce_panel',                'priority' => 20,            ]);            $wp_customize->add_section('aqualuxe_woocommerce_product_section', [                'title' => __('Product', 'aqualuxe'),                'description' => __('Product page settings', 'aqualuxe'),                'panel' => 'aqualuxe_woocommerce_panel',                'priority' => 30,            ]);            $wp_customize->add_section('aqualuxe_woocommerce_cart_section', [                'title' => __('Cart', 'aqualuxe'),                'description' => __('Cart page settings', 'aqualuxe'),                'panel' => 'aqualuxe_woocommerce_panel',                'priority' => 40,            ]);            $wp_customize->add_section('aqualuxe_woocommerce_checkout_section', [                'title' => __('Checkout', 'aqualuxe'),                'description' => __('Checkout page settings', 'aqualuxe'),                'panel' => 'aqualuxe_woocommerce_panel',                'priority' => 50,            ]);            $wp_customize->add_section('aqualuxe_woocommerce_account_section', [                'title' => __('Account', 'aqualuxe'),                'description' => __('Account page settings', 'aqualuxe'),                'panel' => 'aqualuxe_woocommerce_panel',                'priority' => 60,            ]);        }    }    /**     * Preview init     */    public function preview_init() {        wp_enqueue_script(            'aqualuxe-customizer-preview',            AQUALUXE_ASSETS_URI . '/js/customizer.js',            ['customize-preview', 'jquery'],            AQUALUXE_VERSION,            true        );    }    /**     * Controls enqueue scripts     */    public function controls_enqueue_scripts() {        wp_enqueue_script(            'aqualuxe-customizer-controls',            AQUALUXE_ASSETS_URI . '/js/customizer-controls.js',            ['customize-controls', 'jquery'],            AQUALUXE_VERSION,            true        );    }    /**     * Output customizer CSS     */    public function output_customizer_css() {        // Get colors        $primary_color = aqualuxe_get_color('primary');        $secondary_color = aqualuxe_get_color('secondary');        $accent_color = aqualuxe_get_color('accent');        $luxe_color = aqualuxe_get_color('luxe');                // Get typography settings        $body_font_size = aqualuxe_get_option('typography_body_size', '16');        $body_line_height = aqualuxe_get_option('typography_body_line_height', '1.5');        $body_font_weight = aqualuxe_get_option('typography_body_weight', '400');                $h1_font_size = aqualuxe_get_option('typography_h1_size', '36');        $h2_font_size = aqualuxe_get_option('typography_h2_size', '30');        $h3_font_size = aqualuxe_get_option('typography_h3_size', '24');        $headings_font_weight = aqualuxe_get_option('typography_headings_weight', '700');        $headings_transform = aqualuxe_get_option('typography_headings_transform', 'none');                // Get layout settings        $container_width = aqualuxe_get_option('layout_container_width', '1280');        $content_padding = aqualuxe_get_option('layout_content_padding', '80');        $sidebar_width = aqualuxe_get_option('layout_sidebar_width', '30');                // Output CSS        ?>        <style type="text/css">            :root {                --color-primary: <?php echo esc_attr($primary_color); ?>;                --color-secondary: <?php echo esc_attr($secondary_color); ?>;                --color-accent: <?php echo esc_attr($accent_color); ?>;                --color-luxe: <?php echo esc_attr($luxe_color); ?>;                                --font-size-body: <?php echo esc_attr($body_font_size); ?>px;                --line-height-body: <?php echo esc_attr($body_line_height); ?>;                --font-weight-body: <?php echo esc_attr($body_font_weight); ?>;                                --font-size-h1: <?php echo esc_attr($h1_font_size); ?>px;                --font-size-h2: <?php echo esc_attr($h2_font_size); ?>px;                --font-size-h3: <?php echo esc_attr($h3_font_size); ?>px;                --font-weight-headings: <?php echo esc_attr($headings_font_weight); ?>;                --text-transform-headings: <?php echo esc_attr($headings_transform); ?>;                                --container-width: <?php echo esc_attr($container_width); ?>px;                --content-padding: <?php echo esc_attr($content_padding); ?>px;                --sidebar-width: <?php echo esc_attr($sidebar_width); ?>%;                --content-width: calc(100% - <?php echo esc_attr($sidebar_width); ?>%);            }        </style>        <?php    }    /**     * Add general settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_general_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add header settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_header_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add footer settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_footer_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add typography settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_typography_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add colors settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_colors_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add layout settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_layout_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add blog settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_blog_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add social settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_social_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add contact settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_contact_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add performance settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_performance_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add modules settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_modules_settings($wp_customize) {        // Implementation in the full class    }    /**     * Add WooCommerce settings     *     * @param WP_Customize_Manager $wp_customize     */    private function add_woocommerce_settings($wp_customize) {        // Implementation in the full class    }}// Initialize customizerAquaLuxe_Customizer::get_instance();